#!/usr/bin/env python3
"""
清洗并处理原始HTML文本，提取结构化信息
"""

from html.parser import HTMLParser
import re
from datetime import datetime

class HTMLCleaner(HTMLParser):
    def __init__(self):
        super().__init__()
        self.text_parts = []
        self.in_script_style = False
        self.links = []
        self.images = []
        
    def handle_starttag(self, tag, attrs):
        attrs_dict = dict(attrs)
        
        # 提取图片
        if tag == 'img':
            src = attrs_dict.get('src', '')
            if src and src.startswith('http'):
                self.images.append(src)
        
        # 提取链接
        if tag == 'a':
            href = attrs_dict.get('href', '')
            if href and href.startswith('http'):
                self.links.append(href)
        
        # 跳过 script 和 style
        if tag in ['script', 'style']:
            self.in_script_style = True
            
    def handle_endtag(self, tag):
        if tag in ['script', 'style']:
            self.in_script_style = False
        # 段落结束添加换行
        if tag in ['p', 'div', 'h1', 'h2', 'h3', 'h4', 'h5', 'h6', 'blockquote', 'li']:
            self.text_parts.append('\n')
            
    def handle_data(self, data):
        if not self.in_script_style:
            # 清理多余空白但保留结构
            cleaned = data.strip()
            if cleaned:
                self.text_parts.append(cleaned)
    
    def get_text(self):
        text = ' '.join(self.text_parts)
        # 清理多余换行和空格
        text = re.sub(r'\n\s*\n\s*\n', '\n\n', text)
        text = re.sub(r'  +', ' ', text)
        return text.strip()

# 原始HTML内容
html_content = '''<span class="RichText ztext CopyrightRichText-richText css-yzps3a" options="[object Object]" itemprop="text"><p data-first-child="" data-pid="BoczBUQP">《纽约时报》发了一篇非常详尽的文章，标题是《特朗普如何将美国拖入与伊朗的战争》，我们可以看到，在目前白宫的赢学与顺从文化下，事关国家生死存亡的关键决策竟这样如同儿戏。</p><h2>1.秘密报告</h2><p data-pid="BIVrIOdS">2026年2月11日上午接近11点，一辆黑色SUV低调驶入白宫，载着以色列总理本雅明·内塔尼亚胡。此次访问刻意避开媒体视线，没有公开仪式。</p><p data-pid="4eZXqcA1">美以官员先在椭圆形办公室旁的内阁会议室简短会面，随后内塔尼亚胡被带到地下白宫战情室（Situation Room）——这个高度机密的场所极少用于外国领导人的面对面会谈。</p><p data-pid="IracXzBM"> 特朗普没有坐在会议桌主位，而是坐在桌子一侧，面对墙上大屏幕。</p><p data-pid="13ME11P7"> 内塔尼亚胡坐在他对面，正对着总统。</p><p data-pid="UcsyfGE-"> 内塔尼亚胡身后的大屏幕上，实时出现摩萨德局长戴维·巴内亚（David Barnea）和以色列军方官员的身影。营造出"战时领导人被团队簇拥"的视觉效果。</p><p data-pid="5IxMWMQp">以方通过机密通讯技术进行了远程连接。</p><figure data-size="normal"><div class="RichText-ConditionalImagePortal"><img src="https://pic4.zhimg.com/v2-b744e292fe035ab511c9bd5e85544c31_1440w.jpg" data-rawwidth="800" data-rawheight="536" data-size="normal" data-original-token="v2-7cb3a87a4a711bb134fc8d70acb0b322" class="origin_image zh-lightbox-thumb" width="800" data-original="https://pic4.zhimg.com/v2-b744e292fe035ab511c9bd5e85544c31_r.jpg"></div></figure><p data-pid="Ya0804kM"><span class="highlight-wrap other has-comments" data-highlight-id="2026617836345278777" data-highlight-split-type="both" data-highlight-id-extra="">参会核心成员</span>（小范围闭门会议）</p><blockquote data-pid="Z57I1hlT">•  白宫幕僚长苏西·威尔斯<br>•  国务卿兼国家安全顾问马可·卢比奥<br>•  战争部长皮特·赫格塞斯<br>•  参谋长联席会议主席丹·凯恩将军<br>•  CIA局长约翰·拉特克利夫<br>•  特朗普女婿贾里德·库什纳<br>•  中东特使史蒂夫·威特科夫</blockquote><p data-pid="NCGD-Eb7">副总统万斯没有在场，他正在阿塞拜疆访问。玛吉·哈伯曼（Maggie Haberman）说内塔尼亚胡特意挑选这个时间点，目的就是避开万斯副总统，因为他是幕僚中与伊朗开战的明确反对者。</p><p data-pid="cY_C078a">随后，内塔尼亚胡进行了约一小时的高强度陈述，强烈主张伊朗已政权更迭时机成熟。他认为美以联合军事行动能够快速推翻伊斯兰共和国，并描绘了近乎必然胜利的图景：</p><p data-pid="9dXUYVfj">•  伊朗弹道导弹计划可在几周内被摧毁。</p><p data-pid="p3_Jk3QR">•  伊朗政权将被严重削弱，无法封锁<span><a class="RichContent-EntityWord css-b7erz1" data-za-not-track-link="true" data-paste-text="true" href="https://zhida.zhihu.com/search?content_id=777052339&amp;content_type=Answer&amp;match_order=1&amp;q=%E9%9C%8D%E5%B0%94%E6%9C%A8%E5%85%B9%E6%B5%B7%E5%B3%A1&amp;zhida_source=entity" target="_blank">霍尔木兹海峡<svg width="10px" height="10px" viewBox="0 0 16 16" class="ZDI ZDI--FourPointedStar16 css-1dvsrp" fill="currentColor"><path d="m5.068 9.267-3.08-.77a.512.512 0 0 1 0-.994l3.08-.77a2.289 2.289 0 0 0 1.665-1.665l.77-3.08a.512.512 0 0 1 .994 0l.77 3.08c.205.82.845 1.46 1.665 1.665l3.08.77a.512.512 0 0 1 0 .994l-3.08.77a2.29 2.29 0 0 0-1.665 1.665l-.77 3.08a.512.512 0 0 1-.994 0l-.77-3.08a2.289 2.289 0 0 0-1.665-1.665Z"></path></svg></a></span>。</p><p data-pid="vMNaAkt9">•  对美国在中东利益的报复风险极低。</p><p data-pid="C5Axss39">•  以色列情报可帮助在伊朗境内煽动街头抗议，最终实现政权更迭。</p><p data-pid="xnz9hotq">会议中，内塔尼亚胡还播放了一段视频，展示如果神权政府倒台后可能领导伊朗的新人物，包括流亡的<span class="highlight-wrap other has-comments" data-highlight-id="2026624449139458847" data-highlight-split-type="both" data-highlight-id-extra="">伊朗末代沙王之子礼萨·巴列维（Reza Pahlavi）</span>。</p><p data-pid="kst6t1wV">随后，BB向特朗普展示了关于伊朗内部动荡和<span><a class="RichContent-EntityWord css-b7erz1" data-za-not-track-link="true" data-paste-text="true" href="https://zhida.zhihu.com/search?content_id=777052339&amp;content_type=Answer&amp;match_order=1&amp;q=%E5%BA%93%E5%B0%94%E5%BE%B7%E6%AD%A6%E8%A3%85&amp;zhida_source=entity" target="_blank">库尔德武装<svg width="10px" height="10px" viewBox="0 0 16 16" class="ZDI ZDI--FourPointedStar16 css-1dvsrp" fill="currentColor"><path d="m5.068 9.267-3.08-.77a.512.512 0 0 1 0-.994l3.08-.77a2.289 2.289 0 0 0 1.665-1.665l.77-3.08a.512.512 0 0 1 .994 0l.77 3.08c.205.82.845 1.46 1.665 1.665l3.08.77a.512.512 0 0 1 0 .994l-3.08.77a2.29 2.29 0 0 0-1.665 1.665l-.77 3.08a.512.512 0 0 1-.994 0l-.77-3.08a2.289 2.289 0 0 0-1.665-1.665Z"></path></svg></a></span>的情报视频，他声称以色列情报（摩萨德）可悄然支持伊朗国内街头抗议，迅速引发大规模起义，最终导致政权崩溃</p><p data-pid="npESa2L-">同时，他强调伊拉克境内的库尔德武装可以从西北方向打开地面战线，分散伊朗军队注意力并加速其瓦解。</p><p data-pid="mZTmHEK6">特朗普听完后迅速回应：</p><blockquote data-pid="wsIvE9U7">我听着不错。</blockquote><p data-pid="-Fq6QLEi">国务卿卢比奥率先提出质疑，卢比奥根本不相信事情进展会这么顺利，这么简单就能推翻一个美国47年来都无法搞定的政权。他提出质疑，认为和伊朗开战风险太大。</p><p data-pid="KNRqmRcw">内塔尼亚胡则回应：</p><blockquote data-pid="sDyQU7rn">这当然存在风险，但是不采取行动的风险大于采取行动的风险。如果打击推迟，伊朗就能快速研发出核武器，到时候所有的行动都太晚了！</blockquote><p data-pid="dAemh0ZL">他接着说：</p><blockquote data-pid="InaviBXa">经过这两年的<span><a class="RichContent-EntityWord css-b7erz1" data-za-not-track-link="true" data-paste-text="true" href="https://zhida.zhihu.com/search?content_id=777052339&amp;content_type=Answer&amp;match_order=1&amp;q=%E5%8A%A0%E6%B2%99%E6%88%98%E4%BA%89&amp;zhida_source=entity" target="_blank">加沙战争<svg width="10px" height="10px" viewBox="0 0 16 16" class="ZDI ZDI--FourPointedStar16 css-1dvsrp" fill="currentColor"><path d="m5.068 9.267-3.08-.77a.512.512 0 0 1 0-.994l3.08-.77a2.289 2.289 0 0 0 1.665-1.665l.77-3.08a.512.512 0 0 1 .994 0l.77 3.08c.205.82.845 1.46 1.665 1.665l3.08.77a.512.512 0 0 1 0 .994l-3.08.77a2.29 2.29 0 0 0-1.665 1.665l-.77 3.08a.512.512 0 0 1-.994 0l-.77-3.08a2.289 2.289 0 0 0-1.665-1.665Z"></path></svg></a></span>、<span><a class="RichContent-EntityWord css-b7erz1" data-za-not-track-link="true" data-paste-text="true" href="https://zhida.zhihu.com/search?content_id=777052339&amp;content_type=Answer&amp;match_order=1&amp;q=%E9%BB%8E%E5%B7%B4%E5%AB%A9%E6%88%98%E4%BA%89&amp;zhida_source=entity" target="_blank">黎巴嫩战争<svg width="10px" height="10px" viewBox="0 0 16 16" class="ZDI ZDI--FourPointedStar16 css-1dvsrp" fill="currentColor"><path d="m5.068 9.267-3.08-.77a.512.512 0 0 1 0-.994l3.08-.77a2.289 2.289 0 0 0 1.665-1.665l.77-3.08a.512.512 0 0 1 .994 0l.77 3.08c.205.82.845 1.46 1.665 1.665l3.08.77a.512.512 0 0 1 0 .994l-3.08.77a2.29 2.29 0 0 0-1.665 1.665l-.77 3.08a.512.512 0 0 1-.994 0l-.77-3.08a2.289 2.289 0 0 0-1.665-1.665Z"></path></svg></a></span>和内外制裁，伊朗政权如今已经非常虚弱，他们杀死了四万名抗议群众，现在就是彻底终结这个政权的最好时机。</blockquote><p data-pid="apIvfN3c">这时候全场鸦雀无声，内塔尼亚胡自信满满，但完全无法判断真假，特朗普询问自己的<span class="highlight-wrap other has-comments" data-highlight-id="2026930649106260936" data-highlight-split-type="both" data-highlight-id-extra="">驸马爷贾里德库什纳：</span></p><blockquote data-pid="7-au2wt5">你的意见呢？</blockquote><p data-pid="gklIXGQY">库什纳没有回应，特朗普就接过了BB递过来的报告，要求相关官员连夜进行战情分析。</p><h2>2.针锋相对</h2><p data-pid="-LTR2y8x">美国分析人员连夜加班评估内塔尼亚胡提出的内容。第二天（2月12日），他们在另一次战情室会议上给出了直率的结论。</p><p data-pid="i_J2mJf1">中情局局长约翰·拉特克利夫说</p><blockquote data-pid="HRva_lTt">以色列方案中提出的前两个目标——杀死最高领袖并削弱伊朗威胁邻国的能力是可以实现的。但内塔尼亚胡及其团队提出的后两个目标——在伊朗境内引发民众起义，并用新的世俗领导人取代伊斯兰政府——则无法实现。<br><br>目前没有任何的情报显示，推翻现有政权的行动，能在短时间内轻易获得成功。<br><br>这是极其荒谬的意想天开。</blockquote><p data-pid="tNyipakY">卢比奥补充道：</p><blockquote data-pid="nCtXr5ky">（内塔尼亚胡的报告）简直是胡说八道！</blockquote><p data-pid="ytCAvm1V">刚刚从阿塞拜疆外交访问回来的副总统万斯也参加了这个会议，他的态度非常强烈，极力地反对开火。万斯说：</p><blockquote data-pid="RkuKZ0bp">我知道你想这么做，但我认为这是个坏主意</blockquote><p data-pid="iRXgzVmY">他随即长篇大论地阐述了自己的核心观点：</p><ul><li data-pid="fc8EkzlU">内塔尼亚胡对政权更迭的预测太过乐观和不现实，他把事情说得太容易了，实际远没有那么容易实现；</li><li data-pid="i7npSZzl">战争很可能引发地区大规模混乱，造成大量伤亡，并严重消耗美国武器库存；</li><li data-pid="PPSGSw8L">伊朗一旦面临政权存亡威胁，报复行动将难以预测，霍尔木兹海峡极有可能被封锁，导致油价暴涨，伤害美国经济和特朗普的支持者基础；</li><li data-pid="njv-F2Q0">这场战争违背了特朗普"不打新战争"的竞选承诺，会被视为对MAGA选民的背叛；</li><li data-pid="og-xfqov">即使要采取行动，也应该限于压倒性但有限的打击，而不是追求全面政权更迭这种高风险目标。</li></ul><p data-pid="2sVey2FX">特朗普总统旋即转头问美国参谋长联席会议主席唐·凯恩上将：</p><blockquote data-pid="SLZoa0AM">你的意见呢？</blockquote><p data-pid="Df4uVFF6">凯恩上将回答道：</p><blockquote data-pid="irhprr7F">依我的经验，这是以色列的惯用伎俩，他们喜欢夸大其词，但是计划又往往没有那么完美。他们知道需要我们，才这样推销自己。</blockquote><p data-pid="TYVuWd-e">特朗普随后要求凯恩：</p><blockquote data-pid="3nHkSJOI">请提交一份作战评估报告</blockquote><p data-pid="tgTcmpq6">2月12日会议没有达成任何重要结论。当时主战派的战争部长皮特·赫格塞思以及金刀驸马贾里德·库什纳都因故没有在场，如果他们在场，可以和这四位持明显反对意见的重臣进行一场争锋相对的辩论。</p><figure data-size="normal"><div class="RichText-ConditionalImagePortal"><img src="https://pica.zhimg.com/v2-dc41c5897a143d6ce324a62638056b78_1440w.jpg" data-rawwidth="640" data-rawheight="423" data-size="normal" data-original-token="v2-20b665023a3251ad984e6e76efeabed1" class="origin_image zh-lightbox-thumb" width="640" data-original="https://pica.zhimg.com/v2-dc41c5897a143d6ce324a62638056b78_r.jpg"></div></figure><p data-pid="d-uPXRnS">凯恩上将随后向总统提交了战情报告，提出了开战面临的四大风险：</p><ol><li data-pid="JYlhGShK"><b>行动赌注远高于之前任何类似行动</b><br>凯恩明确指出，对伊朗的大规模军事行动（尤其是追求政权更迭目标）赌注比此前委内瑞拉等行动高得多。伊朗是一个拥有强大导弹能力、复杂地形和顽强抵抗意愿的国家，远非轻松目标。他提醒特朗普，这不是一场"速胜"的小规模打击，而是一场可能需要长期投入大量资源的军事冒险。</li><li data-pid="Zghrlt8e"><b>更容易陷入旷日持久的纠缠和长期冲突</b><br>凯恩强调，战争很可能不会像内塔尼亚胡所说的几周内结束，而是容易演变为长期纠缠（prolonged entanglement）。伊朗有能力进行游击战、代理人攻击和持续抵抗，美军可能被拖入一场难以脱身的消耗战，类似过去中东战争的教训。</li><li data-pid="12r15e2E"><b>美军人员伤亡风险明显增加</b><br>他直言，行动中美国士兵的伤亡风险显著高于乐观预期。伊朗的防空系统、弹道导弹和地面力量虽有弱点，但一旦进入全面对抗阶段，美军可能面临更高的人员损失，尤其是在持续空中作战或需要地面支援的情况下。</li><li data-pid="2D4QWOfZ"><b>武器库存消耗严重，后续补给困难</b><br>凯恩特别提醒，美国当前的防空导弹、精确制导弹药、无人机等关键库存已经因长期支援以色列和乌克兰而较为紧张，产能严重不足，大规模对伊朗打击会快速消耗这些储备，短期内难以快速补充。</li></ol><h2>3. 暧昧反对</h2><p data-pid="-h7P77oH">凯恩虽然提交了这份详细的军事风险报告，但他的性格和前任参谋长联席会议主席马克·米利将军完全不同。</p><p data-pid="Blk1-mg8">米利将军是出了名的暴脾气，如果他强烈反对某件事，就会据理力争、寸步不让，甚至不惜以辞职相威胁，也绝不会违心同意。</p><p data-pid="V1ohCK1e">而凯恩的风格则低调务实得多。他更愿意以中立、专业的态度，从纯军事角度把行动的风险和潜在问题摆到桌面，但始终把自己定位成一名参谋军官，而不是决策者。<span class="highlight-wrap other has-comments" data-highlight-id="2026727822547263875" data-highlight-split-type="both" data-highlight-id-extra="">他把最终的决定权完整地留给了特朗普总统，从不越界。</span></p><p data-pid="1ZLcUkeg">他在报告中说：</p><blockquote data-pid="e_9WzpM4">一旦总统最终下令，军队会全力执行，并克服一切困难，在战斗中获胜。但作为军事顾问，参谋长联席会议有责任把真实的风险和难度告诉总统。</blockquote><p data-pid="3OrV18nr">凯恩的整体态度被内部人士描述为清醒的现实派和不情愿的战士（reluctant warrior）。</p><p data-pid="OFH3gAjv">可惜的是，特朗普总统有意或无意地误读了这句话的含义，把凯恩包装成一个支持打击伊朗并确定能获得胜利的参谋长。2026年2月23日，他对媒体说：</p><blockquote data-pid="a45OaBOb">"General Caine, like all of us, would like not to see War but, if a decision is made on going against Iran at a Military level, it is his opinion that it will be something easily won."（ "凯恩将军，和我们所有人一样，都不希望看到战争，但是，如果做出在军事层面上对伊朗采取行动的决定，那么他的意见是：这将是一场很容易获胜的事。"）</blockquote><figure data-size="normal"><div class="RichText-ConditionalImagePortal"><img src="https://pic4.zhimg.com/v2-60feebccb731876eaff157a5e89c2c49_1440w.jpg" data-rawwidth="495" data-rawheight="619" data-size="normal" data-original-token="v2-e81fa0b656a97f3c5028294a4f91ea22" class="origin_image zh-lightbox-thumb" width="495" data-original="https://pic4.zhimg.com/v2-60feebccb731876eaff157a5e89c2c49_r.jpg"></div></figure><p data-pid="Q_afj0V0">要理解这一点，我们可以看《外交政策》杂志4月8日的文章《Iran War Cease-Fire: Why Trump Mishandled Tehran》（伊朗停火：为什么特朗普误判伊朗）, 文章写道：</p><blockquote data-pid="yf64dUTE">理解特朗普在伊朗问题上的惨败，一个关键在于认识到，导致这一错误的种种因素早已酝酿已久。在他第二个任期伊始，负责组建国家安全团队的特朗普官员们将忠诚置于一切之上。他们推行荒谬的"纯洁性测试"，任何有过哪怕最轻微批评特朗普或其政策记录的人都被弃用，即便这些人原本能为未来的职位带来丰富的经验。<br><br>超过1300名国务院雇员被解雇，国家安全委员会也遭到严重削弱。特朗普第二个任期开始几个月后，对白宫拥有巨大影响力的阴谋论者劳拉·卢默发起了一系列旨在罢免高级政策制定者的运动，其中包括内特·斯旺森——这位资深外交官曾是特朗普在伊朗问题上的得力助手。（斯旺森在二月份发表于《外交事务》杂志的一篇文章中，准确地预测了伊朗问题陷入泥潭的风险。）<br><br>特朗普越来越倾向于依靠朋友和家人——今年早些时候，史蒂夫·威特科夫和贾里德·库什纳领导了与伊朗的谈判——而不是职业外交官。<br><br>除了解雇专家之外，特朗普还营造了一种对通过"纯洁性考验"的内阁官员绝对服从的氛围。批评被视为禁忌，公开奉承则受到鼓励。与特朗普的第一个任期一样，但对美国和各国官员而言，这种现象的程度甚至更加严重，谄媚成为了实现个人目标的首选手段。</blockquote><figure data-size="normal"><div class="RichText-ConditionalImagePortal"><img src="https://pica.zhimg.com/v2-1792c8fccfc425142991b1351aacf952_1440w.jpg" data-rawwidth="1290" data-rawheight="1501" data-size="normal" data-original-token="v2-86540727b2f4efd64f9592980d468b2e" class="origin_image zh-lightbox-thumb" width="1290" data-original="https://pica.zhimg.com/v2-1792c8fccfc425142991b1351aacf952_r.jpg"></div></figure><p data-pid="UvawofN6">在《外交政策》另外两篇文章2026年3月2日的《Did Trump Miscalculate on Iran?》（特朗普在伊朗问题上误算了吗？）和2026年3月30日：《Trump Is Losing the War in Iran》（特朗普正在输掉对伊朗的战争）中明确指出了白宫内部这种不报实情、不讲真话的氛围，这种氛围的核心特点是：</p><ul><li data-pid="8jF_VZXi">忠诚测试优先：特朗普身边的核心幕僚大多是通过忠诚测试选出来的。他们知道，如果公开或强烈表达不同意见，很容易被边缘化、公开羞辱，甚至被解雇。</li><li data-pid="sbJy6far">不敢报坏消息：多名内部人士透露，幕僚们普遍害怕告诉特朗普坏消息。无论是情报评估显示的战争风险、武器库存消耗严重、油价暴涨对美国经济的冲击，还是国内民意对战争的支持度下降，都倾向于轻描淡写或只呈现乐观的一面。</li></ul><p data-pid="cSmkuGvv">最<span class="highlight-wrap other has-comments" data-highlight-id="2026597103862859393" data-highlight-split-type="both" data-highlight-id-extra="">明显的例子，就是美国国防部长皮特·赫格塞思，他是对伊朗作战的绝对强硬派，被指责向特朗普展示误导性的精彩集锦，只给他看空袭成功视频，而隐瞒伊朗报复的真实规模和战争的复杂性。内部有人直言：</span></p><blockquote data-pid="SQVf8vuk">Pete没有对总统说真话。</blockquote><p data-pid="adN729yv">白宫幕僚长苏西·威尔斯（Susie Wiles）甚至担心特朗普得到的都是"玫瑰色的乐观画面"，曾私下敦促同事对总统更坦诚一些。</p><blockquote data-pid="YTXfKxhV">他们害怕挑战特朗普的"直觉"，因为过去类似行为往往导致被公开批评或失去职位。</blockquote><p data-pid="QMpZHuL4">这种充满恐惧、顺从与暧昧反对的氛围，严重助长了特朗普对形势的误判。</p><p class="ztext-empty-paragraph"><br></p><h2>4.总统的直觉</h2><p data-pid="Z36F_15k">在他看来，既然身边的人虽然表达了反对，但态度并不激烈、也没有人据理力争，那就说明情况或许并没有那么糟糕。这种模棱两可的反对，极大削弱了对现实风险的预警，同时无形中提高了冒险行为的奖励预期。</p><p data-pid="sA9sX068">特朗普因此逐渐相信：他真的有可能以极小的代价，一举解决这个困扰美国长达47年的头号敌人，从而成为名留青史的伟大总统。</p><p data-pid="idLpMIZ-">对于凯恩上将的这一份充满风险预警的报告，特朗普直接要求：打回重做。———潜台词很明显：<span class="highlight-wrap other has-comments" data-highlight-id="2026600196021269239" data-highlight-split-type="both" data-highlight-id-extra="">给我弄一份更加温和的版本</span>。</p><p data-pid="jxsWbzB1">当反对的杂音不那么刺耳，赞成的呼吁就显得震耳欲聋。</p><p data-pid="QoCMgOYE">赫格塞思向特朗普总统拨打电话，在电话中他说：</p><blockquote data-pid="REWdqI1Z">我们干吧！我们不能允许伊朗获得核武器。</blockquote><figure data-size="normal"><div class="RichText-ConditionalImagePortal"><img src="https://pic2.zhimg.com/v2-05007f727cb8b73099d0053c154c8377_1440w.jpg" data-rawwidth="960" data-rawheight="1200" data-size="normal" data-original-token="v2-9e9260db87f8bf91bdcdd99488db13c0" class="origin_image zh-lightbox-thumb" width="960" data-original="https://pic2.zhimg.com/v2-05007f727cb8b73099d0053c154c8377_r.jpg"></div></figure><p class="ztext-empty-paragraph"><br></p><p data-pid="ON7FJmWH">这位美国战争部长对媒体说：</p><blockquote data-pid="hoaqRMs-">这是一个决定性的时刻。我们掌控天空，必须完成任务。<br><br>我们将在一周内控制伊朗领空，他们的领导人要么死掉，要么躲起来！</blockquote><figure data-size="normal"><div class="RichText-ConditionalImagePortal"><img src="https://pica.zhimg.com/v2-217db8ed8c691894af8e4c344c2ce10a_1440w.jpg" data-rawwidth="1290" data-rawheight="1326" data-size="normal" data-original-token="v2-83a987a5c8b59aa12735346b91401b21" class="origin_image zh-lightbox-thumb" width="1290" data-original="https://pica.zhimg.com/v2-217db8ed8c691894af8e4c344c2ce10a_r.jpg"></div></figure><p class="ztext-empty-paragraph"><br></p><p data-pid="hrfs7L5G">与此同时，随着2月17日美伊的第二轮谈判在日内瓦陷入僵局，国务卿卢比奥的态度也开始发生转变。</p><p data-pid="aZE829LV">美国国务卿在匈牙利说：</p><blockquote data-pid="yEnSeS32">（与伊朗的谈判）将会很困难。对任何人来说，与伊朗达成真正的协议一直都非常困难，因为我们面对的是一些激进的什叶派神棍，他们做出的决定是基于神学，而不是地缘政治。</blockquote><figure data-size="normal"><div class="RichText-ConditionalImagePortal"><img src="https://pic1.zhimg.com/v2-4d15c4161ec973edb424e926d0b48690_1440w.jpg" data-rawwidth="1290" data-rawheight="1328" data-size="normal" data-original-token="v2-882770f47b8f863ad90de42dea54cc71" class="origin_image zh-lightbox-thumb" width="1290" data-original="https://pic1.zhimg.com/v2-4d15c4161ec973edb424e926d0b48690_r.jpg"></div></figure><p data-pid="bBxvWx9h">卢比奥这样的反转可不是头一遭，他最终屈服于总统的直觉。</p><p data-pid="XbBB18Er">事实上，特朗普在第二任期身边围绕的顾问们视他为历史伟人。</p><p data-pid="C9BOtKzO">在2024年不可思议的东山再起之后，在经历多次起诉和暗杀未遂之后，在下令成功实施抓捕马杜罗的完美行动之后，特朗普身边的人对他命运、直觉以及他让现实屈服于自己意志的能力产生了近乎迷信的信仰。</p><p data-pid="Wrdl6CIf">在这个高风险、高赌注的决定中，几乎所有人都服从了总统的直觉。</p><p data-pid="lSvND7hi">于是在2月21日的战情会议上，当凯恩上将继续重复他的观点时，赫格塞思直接打断说：</p><blockquote data-pid="FMihHy40">当时所有人都反对抓捕马杜罗的决策，但结果大家也都看到了——行动非常顺利，代价远比预想的小。<br><br>现在对伊朗也是一样。<br><br>我们要做的，就是快速、果断地完成这项行动，别再拖拖拉拉。</blockquote><p data-pid="LjHo1QVx"><span class="highlight-wrap other" data-highlight-id="2026916084872135827" data-highlight-split-type="both" data-highlight-id-extra="">当最高领导人冒着巨大风险、违背几乎所有幕僚的常识和建议，做出与众人截然相反的决策，却一次又一次被现实证明是正确的，那么他的权威就会变得毋庸置疑。</span></p><p data-pid="aLg8zXJ3"><span class="highlight-wrap other has-comments" data-highlight-id="2026591795413366460" data-highlight-split-type="both" data-highlight-id-extra="">第二次世界大战初期，希特勒不顾将军们的强烈反对，多次做出冒险的军事决策，却接连取得惊人胜利。从那以后，德国军方和高层几乎再也没有人敢公开质疑他了。</span></p><h2>5. 决策出兵</h2><p data-pid="6C_UMQTS">2月26日，最后一次战前会议在白宫召开。</p><p data-pid="YI-9yO1q">副总统万斯第一个发言，他说：</p><blockquote data-pid="fdYRYT3X">你知道我认为这是个坏主意，但是如果你真的想要这么做，我支持你。</blockquote><p data-pid="noNLqHYR">国务卿卢比奥第二个发言，他说：</p><blockquote data-pid="XbuS8H_X">虽然我认为这存在一定的风险，但是总统您认为这是为了美国国家安全必须采取的行动的话，那就应该去做。</blockquote><p data-pid="ncPq9lJt">特朗普总统询问道：</p><blockquote data-pid="MM3DfWAs">可是你之前可不是这么说的</blockquote><p data-pid="JcbpMnGE">卢比奥回答：</p><blockquote data-pid="r6-XmC6s">事实证明，他们在谈判桌上耍了我们，毫无诚意可言，他们在把全世界当作人质，现在是做出最终决策的时候了。</blockquote><p data-pid="ZIxmnCjW">当这两位最重量级人物都如此表态，那其他人就更不敢表示反对了。</p><p data-pid="6cK2FjJG">中情局局长拉特克里夫第三个发言，他说：</p><blockquote data-pid="iVrlfwo9">我们需要明确定义何为颠覆伊朗现政权。如果是杀了现任这批伊朗官员的话，我认为是可行的。</blockquote><p data-pid="v-J_5i92">白宫高级法律顾问沃灵顿第四个发言，他说：</p><blockquote data-pid="7GncxnY9">总统与伊朗开战在法律角度没有任何问题</blockquote><p data-pid="rXoHo-IL">特朗普追问：</p><blockquote data-pid="2trH5jKY">你认为应该开战吗？</blockquote><p data-pid="XIVYQgxP">沃灵顿回答：</p><blockquote data-pid="pdFVQH7E">是的，如果以色列这么做了，那我们也应当如此</blockquote><p data-pid="xkJOd1r1">白宫通讯主任史蒂文·张第五个发言，他说：</p><blockquote data-pid="vHheoePu">总统先生，去做您认为正确的事吧，白宫新闻团队会妥善处理后续事宜</blockquote><p data-pid="IZ-bCl77">国防部长皮特·赫格塞思第六个发言，他说：</p><blockquote data-pid="Gu1fBnZE">早晚都会和伊朗开战的，现在是最佳时机。这个政权刚刚杀了四万人。</blockquote><p data-pid="dyXIFQfu">他继续补充道：</p><blockquote data-pid="QJ7MP5Ka">我们现有的力量完全可以完成这个行动</blockquote><p data-pid="Hb0gnW-K">美国参谋联席会议主席丹·凯恩上将第七个发言，他阐述了此次行动的风险以及其对伊朗军备消耗的影响和风险。他没有发表任何意见；他的立场是，如果特朗普总统下令开展行动，军方将执行。总统的两名高级军事将领预先介绍了此次行动的展开方式以及美国削弱伊朗军事能力的潜力。</p><p data-pid="7cL8_zoG">特朗普总统做了最后的总结，他说</p><blockquote data-pid="fb5_6I54">我们必须这样做。我们必须确保伊朗没有核武器，也必须确保伊朗不能向以色列发射导弹。</blockquote><p data-pid="-lpDXfT0">针对伊朗的开战计划得到通过。</p><p data-pid="deblUZVJ">旋即，特朗普总统在他的真实社交上发推说：</p><blockquote data-pid="9_-QJXtS">"I'm not happy with the Iran nuclear talks. They are not giving us what we need. Not thrilled at all. We'll see what happens. We're talking later tonight. But if they don't make a real deal, bad things will happen — very bad things. Iran has been playing games for too long."</blockquote><p class="ztext-empty-paragraph"><br></p><h2>6. 战略误判</h2><p data-pid="dmkPtgEe">2月28日，在几乎没有完成任何准备的情况下，美军发动代号"史诗狂怒"的军事行动，美伊战争正式爆发。</p><p data-pid="VMLHl8dw">截至4月9日，美国至少28人死亡，468人受伤，其中18人重伤。</p><p data-pid="EWszKCnt">空中力量方面：</p><ul><li data-pid="6jBktV0Y">四架F15E战斗机损毁，累计损失9300万美元。</li><li data-pid="pV0ZR8Um">三架KC135R空中加油机损毁，累计损失2.7亿美元。</li><li data-pid="3t9yb-KI">一架E3G哨兵预警机损毁，系美军在中东雷达的预警中枢，全球仅存16架且无法再生产，损失超7亿美元。</li><li data-pid="90j9eDb1">两架EC130电子战飞机损毁。</li><li data-pid="Tk4cYAGq">14架MQ-9死神察打一体无人机损毁，累计损失4.48亿美元。</li><li data-pid="mQlwx0Hr">两架黑鹰直升机坠毁，损失超过0.53亿美元。</li><li data-pid="fI5fCguZ">两架MC130运输机损毁，损失超2.28亿美元。</li><li data-pid="bSrthrpe">四架MH6小鸟直升机损毁，损失约0.3亿美元。</li><li data-pid="mQInAsbl">一架A10 疣猪攻击机损毁。</li></ul><p data-pid="q8KnsidW">在防空反导体系方面，伊朗的打击直接击碎了美军耗资数千亿、耗时数十年打造的中东反导体系神话，损失包括：</p><ul><li data-pid="ubECjvmD">一套位于卡塔尔<span><a class="RichContent-EntityWord css-b7erz1" data-za-not-track-link="true" data-paste-text="true" href="https://zhida.zhihu.com/search?content_id=777052339&amp;content_type=Answer&amp;match_order=1&amp;q=%E4%B9%8C%E4%BB%A3%E5%BE%B7%E7%A9%BA%E5%86%9B%E5%9F%BA%E5%9C%B0&amp;zhida_source=entity" target="_blank">乌代德空军基地<svg width="10px" height="10px" viewBox="0 0 16 16" class="ZDI ZDI--FourPointedStar16 css-1dvsrp" fill="currentColor"><path d="m5.068 9.267-3.08-.77a.512.512 0 0 1 0-.994l3.08-.77a2.289 2.289 0 0 0 1.665-1.665l.77-3.08a.512.512 0 0 1 .994 0l.77 3.08c.205.82.845 1.46 1.665 1.665l3.08.77a.512.512 0 0 1 0 .994l-3.08.77a2.29 2.29 0 0 0-1.665 1.665l-.77 3.08a.512.512 0 0 1-.994 0l-.77-3.08a2.289 2.289 0 0 0-1.665-1.665Z"></path></svg></a></span>的铺路爪战略预警雷达，造价11.2亿美元。探测距离达5000km，其损毁直接导致美军在中东的导弹探测预警窗口缩短60%。</li><li data-pid="abV6vpIA">十三套爱国者防空系统的雷达车与发射车损毁或不可逆重伤，损失超70亿美元。</li><li data-pid="HNaiaSJP">一套部署于阿联酋的萨德反导系统核心雷达完全损毁。</li><li data-pid="3NencH4R">十七座中东美军基地的核心设施被直接命中。</li><li data-pid="dRVDFEQF">巴林萨勒曼港的美军第五舰队总部核心设施遭到损毁。</li></ul><p data-pid="RTS-qyMp">另外 ，如甲骨文、亚马逊在海湾地区的数据中心、联邦快递在阿联酋的物流中心、环球铝业（EGA）在阿布扎比的工厂等美国资产遭受不同程度的打击。</p><p data-pid="1TmrkuR7">霍尔木兹海峡遭到封锁，油价暴涨，Brent原油价格一度突破126美元。全球24%的原油和20%的天然气供应断裂，全球陷入能源危机。</p><p data-pid="tTlzsrBm">美军遭受了战术硬损失、体系能力损伤、战略信誉崩塌的三重打击，遭受了越南战争以来美军在中东的最大军事损失。伊朗摧毁了美军在中东不可战胜的霸权神话，动摇了美军在中东经营多年的地缘政治根基。</p><p data-pid="vnFZMdkP"><span class="highlight-wrap other has-comments" data-highlight-id="2026745889935357363" data-highlight-split-type="both" data-highlight-id-extra="">与此同时，美军亦完成了伊朗政权的更迭———从老哈梅内伊政权更迭成了小哈梅内伊政权。</span></p><p class="ztext-empty-paragraph"><br></p><p data-pid="LgJcejcf">参考文献：</p><p data-pid="sxaSBPQY">•  How Trump Took the U.S. to War With Iran, The New York Times (April 7, 2026)</p><p data-pid="t73mXDqZ">•  6 Takeaways From the Story of Trump's Decision to Go to War With Iran, The New York Times (April 7, 2026)</p><p data-pid="aaMgDurx">•  How Trump and His Advisers Miscalculated Iran's Response to War, The New York Times (March 10, 2026)</p><p data-pid="lkMNAs4k">•  Iran War Cease-Fire: Why Trump Mishandled Tehran, Foreign Policy (April 8, 2026)</p><p data-pid="r5uwPT_e">•  Did Trump Miscalculate on Iran?, Foreign Policy (March 2, 2026)</p><p data-pid="IquPglib">•  Trump Is Losing the War in Iran, Foreign Policy (March 30, 2026)</p><p data-pid="CIL_CeU_">•  Trump's Confusing Iran War Objectives, Foreign Policy (March 5, 2026)</p><p data-pid="HZCW5-iG">•  Trump's Recipe for Accelerated U.S. Decline, Foreign Policy (April 9, 2026)</p><p data-pid="73WikLv3">•  2025–2026 Iran–United States Negotiations, Wikipedia</p><p data-pid="uoDUdTiP">•  Regime Change: Inside the Imperial Presidency of Donald Trump (forthcoming book referenced in NYT reporting)</p></span><span id="VirtualCatalogAnchorPoint"></span>'''

